def validate_edad(edad):
    if edad is None:
        return {"status": "review", "code": "MISSING"}
    if not isinstance(edad, int) or isinstance(edad, bool):
        return {"status": "reject", "code": "BAD_TYPE"}
    if edad < 18 or edad > 120:
        return {"status": "reject", "code": "OUT_OF_RANGE"}
    if edad < 21:
        return {"status": "review", "code": "NEEDS_REVIEW"}
    return {"status": "accept", "code": "OK"}

for e in [None, "25", 15, 30]:
    print(e, "→", validate_edad(e))

def validate_monto_nested(m):
    if m is not None:
        if isinstance(m, int):
            if m >= 0:
                if m <= 10000:
                    return "accept"
                else:
                    return "review"
            else:
                return "reject"
        else:
            return "reject"
    else:
        return "review"

def validate_monto_guards(m):
    if m is None:
        return "review"
    if not isinstance(m, int) or isinstance(m, bool):
        return "reject"
    if m < 0:
        return "reject"
    if m <= 10000:
        return "accept"
    return "review"

for v in [None, "x", -1, 0, 500, 20000]:
    a, b = validate_monto_nested(v), validate_monto_guards(v)
    print(v, a, b, "ok=", a == b)

def etiqueta_bug(x):
    if x != 0:
        if x > 0:
            return "positivo"
        return "negativo"
    elif x == 0:  # nunca se alcanza: x==0 cae en if False y no entra al elif del mismo if
        return "cero"
    return "???"

print("bug 0 →", etiqueta_bug(0))
print("bug 3 →", etiqueta_bug(3))
print("rama muerta: elif x == 0 bajo if x != 0 — cuando x==0 el if es False y el elif tampoco corre de forma útil en anidado; aquí el elif es hermano y SÍ corre para 0, pero el patrón confunde: mejor if/elif/else planos.")

