def gate_cliente(edad, region, tipos_ok):
    if edad is None or region is None:
        return "review"
    if not isinstance(edad, int) or edad < 18:
        return "reject"
    if region not in {"Lima", "Arequipa", "Cusco", "Piura"}:
        return "review"
    if not tipos_ok:
        return "reject"
    return "accept"

