RULES = [
    ("missing_edad", lambda r: r.get("edad") is None, "review"),
    ("underage", lambda r: isinstance(r.get("edad"), int) and r["edad"] < 18, "reject"),
    ("ok", lambda r: True, "accept"),
]

def apply_rules(row):
    for name, pred, status in RULES:
        if pred(row):
            return name, status
    return "none", "review"

for row in [{"edad": None}, {"edad": 15}, {"edad": 40}]:
    print(row, "→", apply_rules(row))

# Matriz de decisión sintética (edad x región allowlist)
# Filas: edad None / <18 / >=18
# Cols: region None / not allowed / allowed
# Política: missing→review; underage→reject; región mala→review; else accept

def decide(edad, region, allowed={"Lima", "Cusco"}):
    if edad is None or region is None:
        return "review"
    if not isinstance(edad, int) or edad < 18:
        return "reject"
    if region not in allowed:
        return "review"
    return "accept"

print("tabla:")
for edad in [None, 16, 30]:
    for region in [None, "Tacna", "Lima"]:
        print(edad, region, "→", decide(edad, region))

def validate_row(row: dict) -> dict:
    errors = []
    if row.get("nombres") is None or str(row.get("nombres")).strip() == "":
        errors.append("nombres missing")
    edad = row.get("edad")
    if edad is None:
        errors.append("edad missing")
    elif not isinstance(edad, int) or isinstance(edad, bool):
        errors.append("edad bad type")
    elif edad < 18:
        errors.append("edad underage")
    status = "reject" if any("underage" in e or "bad" in e for e in errors) else (
        "review" if errors else "accept"
    )
    return {"status": status, "errors": errors}

print(validate_row({"nombres": "Ana", "edad": 30}))
print(validate_row({"nombres": "", "edad": None}))
print(validate_row({"nombres": "Luis", "edad": 15}))

def batch_validate(rows):
    out = []
    for r in rows:
        if r.get("id") is None:
            out.append({**r, "status": "review", "reason": "missing id"})
            continue
        out.append({**r, "status": "accept", "reason": None})
    return out

print(batch_validate([{"id": "C1"}, {"id": None}, {"id": "C2"}]))
